from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Database connection configuration
DB_CONFIG = {
    'host': 'your_host',
    'database': 'your_database',
    'user': 'your_user',
    'password': 'your_password'
}

@app.route('/query', methods=['GET'])
def dynamic_query():
    # Get parameters from request
    table_name = request.args.get('table')
    columns = request.args.get('columns')
    filter_conditions = request.args.get('conditions')

    if not all([table_name, columns]):
        return jsonify({'error': 'Table name and columns are required'}), 400

    # Create SQL query
    columns_list = [col.strip() for col in columns.split(',')]
    sql_columns = ', '.join(columns_list)
    
    where_clause = ''
    if filter_conditions:
        conditions_list = [cond.strip() for cond in filter_conditions.split(' and ')]
        where_clause = ' WHERE ' + ' AND '.join(conditions_list)

    query = f"SELECT {sql_columns} FROM {table_name}{where_clause}"

    # Connect to the database
    conn = None
    try:
        conn = psycopg2.connect(**DB_CONFIG)
        cursor = conn.cursor()
        cursor.execute(query)
        result = cursor.fetchall()
        columns = [desc[0] for desc in cursor.description]
        
        return jsonify({columns: result})

    except (Exception, psycopg2.DatabaseError) as error:
        return jsonify({'error': str(error)}), 500

    finally:
        if conn is not None:
            cursor.close()
            conn.close()

if __name__ == '__main__':
    app.run(debug=True)